const src = $input.first().json;
const body = src.body || src;

const textValue = typeof body.text === 'string'
  ? body.text
  : (body.text?.message || body.conversation || body.message || '');

const message = String(textValue || '').trim();
const rawPhone = String(body.phone || body.chatId || body.from || '').trim();
const digits = rawPhone.replace(/\D/g, '');
const phone = digits ? (digits.startsWith('55') ? digits : `55${digits}`) : '';
const name = String(body.senderName || body.pushName || body.name || 'Cliente').trim() || 'Cliente';
const messageId = String(body.messageId || body.id || '').trim();
const ignore = Boolean(
  body.fromMe === true ||
  body.fromApi === true ||
  body.isGroup === true ||
  body.isNewsletter === true ||
  body.reaction ||
  !message ||
  !phone
);

return [{
  json: {
    rawBody: body,
    phone,
    name,
    message,
    messageLower: message.toLowerCase(),
    messageId,
    ignore,
    stateKey: `pousinox:state:${phone}`,
    leadKey: `pousinox:lead:${phone}`
  }
}];

const https = require('https');

const incoming = $('Normalizar Entrada').first().json;
const redisInput = $input.first().json || {};
const nowIso = new Date().toISOString();

const CONFIG = {
  companyName: 'Pousinox',
  commercialPhone: '5535999619463',
  productName: 'Fixador de Porcelanato',
  price430: 12.00,
  price304: 15.00,
  bonusQtyMin: 50,
  bonusPerPiece: 0.05,
  freeShippingStates: ['MG', 'SP', 'RJ'],
  freeShippingQtyAbove: 100,
  specialConditionQtyAbove: 200,
  pagbankUrl: 'https://pousinox.sualojaonline.app',
  originCep: '37550000',
  melhorEnvioToken: ''
};

function parseStoredState(raw) {
  const candidates = [raw.value, raw.data, raw.propertyName, raw.result, raw.redisValue, raw];
  for (const candidate of candidates) {
    if (!candidate) continue;
    if (typeof candidate === 'object' && !Array.isArray(candidate) && (candidate.stage || candidate.mode)) return candidate;
    if (typeof candidate === 'string') {
      const cleaned = candidate.replace(/^=+/, '').trim();
      if (!cleaned) continue;
      try {
        const parsed = JSON.parse(cleaned);
        if (parsed && typeof parsed === 'object') return parsed;
      } catch (e) {}
    }
  }
  return null;
}

function formatMoney(value) {
  return Number(value || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function isHumanRequest(text) {
  const t = String(text || '').toLowerCase().trim();
  return ['2', '9', 'humano', 'atendente', 'consultor', 'vendedor', 'pessoa',
    'falar com humano', 'falar com atendente', 'quero falar com atendente',
    'quero falar com humano'].includes(t);
}

function onlyDigits(value) {
  return String(value || '').replace(/\D/g, '');
}

function parseQty(message) {
  const qty = parseInt(onlyDigits(message), 10);
  return Number.isFinite(qty) ? qty : NaN;
}

function parseThickness(message) {
  const normalized = String(message || '').replace(',', '.');
  const match = normalized.match(/\d+(\.\d+)?/);
  if (!match) return NaN;
  return Number(match[0]);
}

function requestJson(url, options = {}, payload = null) {
  return new Promise((resolve, reject) => {
    const req = https.request(url, options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          const parsed = data ? JSON.parse(data) : {};
          resolve({ statusCode: res.statusCode, data: parsed, raw: data });
        } catch (err) {
          resolve({ statusCode: res.statusCode, data: null, raw: data });
        }
      });
    });
    req.on('error', reject);
    if (payload) req.write(payload);
    req.end();
  });
}

async function consultarCep(cep) {
  const clean = onlyDigits(cep);
  const url = `https://viacep.com.br/ws/${clean}/json/`;
  const result = await requestJson(url, { method: 'GET' });
  if (!result || result.statusCode >= 400 || !result.data || result.data.erro) return null;
  return result.data;
}

async function cotarMelhorEnvio(toCep, quantity, unitPrice) {
  if (!CONFIG.melhorEnvioToken || !CONFIG.originCep) {
    return {
      mode: 'manual',
      label: 'Vamos cotar o melhor envio para sua região.',
      price: null, service: null, deliveryRange: null,
      warning: 'Configure MELHOR_ENVIO_TOKEN e POUSINOX_ORIGIN_CEP para cotação automática.'
    };
  }
  const weight = Math.max(0.3, Number((quantity * 0.036).toFixed(3)));
  const height = Math.min(25, Math.max(2, Math.ceil(quantity / 40)));
  const payload = {
    from: { postal_code: CONFIG.originCep },
    to: { postal_code: onlyDigits(toCep) },
    products: [{
      id: 'fixador-porcelanato', width: 12, height, length: 18, weight,
      insurance_value: Number((quantity * unitPrice).toFixed(2)), quantity: 1
    }],
    options: { receipt: false, own_hand: false, collect: false },
    services: '1,2,17,18'
  };
  const result = await requestJson(
    'https://www.melhorenvio.com.br/api/v2/me/shipment/calculate',
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
        'Authorization': `Bearer ${CONFIG.melhorEnvioToken}`,
        'User-Agent': 'n8n-pousinox-bot'
      }
    },
    JSON.stringify(payload)
  );
  if (!result || result.statusCode >= 400 || !Array.isArray(result.data)) {
    return { mode: 'manual', label: 'Vamos cotar o melhor envio para sua região.', price: null, service: null, deliveryRange: null };
  }
  const valid = result.data
    .filter(item => item && !item.error && Number(item.price) > 0)
    .sort((a, b) => Number(a.price) - Number(b.price));
  if (!valid.length) {
    return { mode: 'manual', label: 'Vamos cotar o melhor envio para sua região.', price: null, service: null, deliveryRange: null };
  }
  const best = valid[0];
  return {
    mode: 'quoted',
    label: `Melhor envio via ${best.name || best.company?.name || 'transportadora'}`,
    price: Number(best.price),
    service: best.name || best.company?.name || 'Transportadora',
    deliveryRange: best.delivery_range || { min: best.delivery_time || null, max: best.delivery_time || null },
    raw: best
  };
}

function menuMessage() {
  return `Olá! 👋 Bem-vindo à *${CONFIG.companyName}*\n\nTrabalhamos com *fixador de porcelanato* em inox. Cada peça acompanha *bucha prego*.\n\nComo posso te ajudar?\n\n1️⃣ Solicitar orçamento\n2️⃣ Falar com alguém da equipe\n\nDigite 0 para voltar ao menu a qualquer momento.`;
}

function humanAck() {
  return `Perfeito! 👨‍💼 Vou encaminhar seu atendimento para nosso consultor.\n\nEm instantes um humano continua com você por aqui.`;
}

function buildTags(data) {
  const tags = [];
  if (data.code) tags.push(data.code);
  if (data.state) tags.push(`uf_${String(data.state).toLowerCase()}`);
  if (data.specialCondition) tags.push('acima_200');
  if (data.shipping?.mode === 'free') tags.push('frete_gratis');
  if (data.mode === 'human') tags.push('aguardando_humano');
  if (data.quantity > CONFIG.bonusQtyMin) tags.push('bonus_volume');
  return [...new Set(tags)].join(',');
}

function buildSellerLeadMessage(data, title = 'Novo lead Pousinox') {
  const lines = [
    `📌 *${title}*`,
    `👤 Nome: ${data.name || 'Não informado'}`,
    `📱 WhatsApp: ${data.phone || 'Não informado'}`,
  ];
  if (data.inoxLabel) lines.push(`🔩 Inox: ${data.inoxLabel}`);
  if (data.thicknessLabel) lines.push(`📐 Espessura: ${data.thicknessLabel}`);
  if (data.quantity) lines.push(`📦 Quantidade: ${data.quantity} un.`);
  if (data.cep) lines.push(`📮 CEP: ${data.cep}`);
  if (data.city || data.state) lines.push(`📍 Local: ${data.city || ''}/${data.state || ''}`.replace(/\/$/, ''));
  if (data.shippingText) lines.push(`🚚 Frete: ${data.shippingText}`);
  if (data.totalText) lines.push(`💰 Total: ${data.totalText}`);
  if (data.specialCondition) lines.push(`⭐ Condição especial: pedido acima de 200 unidades.`);
  lines.push(`🕒 Etapa: ${data.stage || 'sem etapa'}`);
  return lines.join('\n');
}

const stored = parseStoredState(redisInput) || { stage: 'menu', mode: 'bot' };
let state = { ...stored };

const firstContactAt = state.firstContactAt || nowIso;
const leadCreatedAt = state.leadCreatedAt || nowIso;

const base = {
  ...incoming,
  stage: state.stage || 'menu',
  mode: state.mode || 'bot',
  customerMessage: null,
  sellerMessage: null,
  sendCustomer: false,
  sendSeller: false,
  saveLead: true,
  saveState: true,
  leadStatus: 'em_atendimento',
  quote: null,
  leadRow: null,
  eventRow: null
};

function finalPayload(nextState, extras = {}) {
  const safeState = {
    ...nextState,
    firstContactAt,
    leadCreatedAt,
    updatedAt: nowIso,
    lastInteractionAt: nowIso,
    phone: incoming.phone,
    name: incoming.name
  };

  const leadRowBase = {
    phone: incoming.phone,
    name: incoming.name,
    status: extras.leadStatus || 'em_atendimento',
    stage: safeState.stage || 'menu',
    mode: safeState.mode || 'bot',
    inox: safeState.label || '',
    thickness: safeState.thicknessLabel || '',
    quantity: safeState.quantity || '',
    cep: safeState.cep || '',
    city: safeState.city || '',
    state: safeState.state || '',
    subtotal: safeState.subtotal || '',
    discount: safeState.discount || '',
    shipping_mode: safeState.shipping?.mode || '',
    shipping_price: safeState.shipping?.price ?? '',
    shipping_service: safeState.shipping?.service || '',
    total: safeState.total || '',
    special_condition: safeState.specialCondition ? 'sim' : 'não',
    tags: buildTags(safeState),
    pagbank_url: CONFIG.pagbankUrl,
    first_contact_at: firstContactAt,
    last_interaction_at: nowIso,
    updated_at: nowIso,
    source: 'whatsapp_zapi'
  };

  const eventRowBase = {
    timestamp: nowIso,
    phone: incoming.phone,
    name: incoming.name,
    stage: safeState.stage || 'menu',
    event_type: extras.eventType || 'mensagem_recebida',
    customer_message: incoming.message,
    bot_message: extras.customerMessage || '',
    status: extras.leadStatus || 'em_atendimento'
  };

  return [{
    json: {
      ...base,
      ...extras,
      stage: safeState.stage,
      mode: safeState.mode,
      stateKey: incoming.stateKey,
      leadKey: incoming.leadKey,
      stateToSave: safeState,
      leadSnapshot: leadRowBase,
      leadRow: leadRowBase,
      eventRow: eventRowBase
    }
  }];
}

async function main() {
  const msg = incoming.message;
  const msgLower = incoming.messageLower;

  if (msgLower === '#reset') {
    state = { stage: 'menu', mode: 'bot', firstContactAt, leadCreatedAt };
    return finalPayload(state, {
      customerMessage: `✅ Atendimento automático reativado.\n\n${menuMessage()}`,
      sendCustomer: true, leadStatus: 'resetado', eventType: 'reset'
    });
  }

  if ((state.mode || 'bot') === 'human' && msgLower !== '#reset') {
    return finalPayload(state, {
      sendCustomer: false, sendSeller: false,
      leadStatus: 'aguardando_humano', eventType: 'mensagem_em_handoff'
    });
  }

  if (msgLower === '0' || msgLower === 'menu') {
    state = { stage: 'menu', mode: 'bot', firstContactAt, leadCreatedAt };
    return finalPayload(state, {
      customerMessage: menuMessage(), sendCustomer: true,
      leadStatus: 'menu', eventType: 'menu'
    });
  }

  if (isHumanRequest(msgLower)) {
    state = { ...state, stage: 'human', mode: 'human', firstContactAt, leadCreatedAt };
    return finalPayload(state, {
      customerMessage: humanAck(),
      sellerMessage: buildSellerLeadMessage({
        ...state, name: incoming.name, phone: incoming.phone,
        inoxLabel: state.label,
        totalText: state.total ? formatMoney(state.total) : '',
        shippingText: state.shipping?.mode === 'free' ? 'Frete grátis' : state.shipping?.service || ''
      }, 'Cliente pediu atendimento humano'),
      sendCustomer: true, sendSeller: true,
      leadStatus: 'aguardando_humano', eventType: 'handoff_humano'
    });
  }

  const stage = state.stage || 'menu';

  if (stage === 'menu') {
    if (['1', 'orcamento', 'orçamento', 'fixador', 'fixadores'].includes(msgLower)) {
      state = { ...state, stage: 'ask_inox', mode: 'bot', firstContactAt, leadCreatedAt };
      return finalPayload(state, {
        customerMessage: `Perfeito! Vamos montar seu orçamento de *fixador de porcelanato*.\n\nQual inox você precisa?\n\n1️⃣ *Inox 430* — uso geral, melhor custo-benefício\n2️⃣ *Inox 304* — ideal para ambientes litorâneos\n\n_Obs.: cada peça acompanha bucha prego._`,
        sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'inicio_orcamento'
      });
    }
    return finalPayload({ stage: 'menu', mode: 'bot', firstContactAt, leadCreatedAt }, {
      customerMessage: menuMessage(), sendCustomer: true,
      leadStatus: 'menu', eventType: 'menu'
    });
  }

  if (stage === 'ask_inox') {
    const inoxMap = {
      '1': { code: 'inox_430', label: 'Inox 430', unitPrice: CONFIG.price430 },
      '2': { code: 'inox_304', label: 'Inox 304', unitPrice: CONFIG.price304 }
    };
    const selected = inoxMap[msgLower];
    if (!selected) {
      return finalPayload(state, {
        customerMessage: `Por favor, escolha uma opção válida:\n\n1️⃣ Inox 430\n2️⃣ Inox 304`,
        sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'validacao_inox'
      });
    }
    state = { ...state, ...selected, stage: 'ask_thickness', firstContactAt, leadCreatedAt };
    return finalPayload(state, {
      customerMessage: `Entendi 👍\n\nQual é a espessura do porcelanato?\n\n1️⃣ *7 mm*\n2️⃣ *8 mm ou mais*\n\nSe for acima de 8 mm, vou pedir a medida exata em seguida.`,
      sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'coleta_espessura'
    });
  }

  if (stage === 'ask_thickness') {
    if (msgLower === '1') {
      state = { ...state, thicknessMm: 7, thicknessLabel: '7 mm', stage: 'ask_qty', firstContactAt, leadCreatedAt };
      return finalPayload(state, {
        customerMessage: `Perfeito. Agora me informe a *quantidade aproximada* de peças que você precisa.\n\n_Ex.: 80_`,
        sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'coleta_quantidade'
      });
    }
    if (msgLower === '2') {
      state = { ...state, stage: 'ask_thickness_exact', firstContactAt, leadCreatedAt };
      return finalPayload(state, {
        customerMessage: `Me informe a *espessura exata do porcelanato* em milímetros.\n\n_Ex.: 9,5 mm_`,
        sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'coleta_espessura_exata'
      });
    }
    return finalPayload(state, {
      customerMessage: `Por favor, responda:\n\n1️⃣ 7 mm\n2️⃣ 8 mm ou mais`,
      sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'validacao_espessura'
    });
  }

  if (stage === 'ask_thickness_exact') {
    const mm = parseThickness(msg);
    if (!Number.isFinite(mm) || mm < 8) {
      return finalPayload(state, {
        customerMessage: `Não consegui entender a espessura.\n\nPor favor, envie no formato: *8*, *8,5* ou *9 mm*.`,
        sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'validacao_espessura_exata'
      });
    }
    state = { ...state, thicknessMm: mm, thicknessLabel: `${String(mm).replace('.', ',')} mm`, stage: 'ask_qty', firstContactAt, leadCreatedAt };
    return finalPayload(state, {
      customerMessage: `Perfeito. Agora me informe a *quantidade aproximada* de peças que você precisa.\n\n_Ex.: 80_`,
      sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'coleta_quantidade'
    });
  }

  if (stage === 'ask_qty') {
    const qty = parseQty(msg);
    if (!Number.isFinite(qty) || qty <= 0) {
      return finalPayload(state, {
        customerMessage: `Me envie a *quantidade* somente em número.\n\n_Ex.: 120_`,
        sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'validacao_quantidade'
      });
    }
    state = { ...state, quantity: qty, stage: 'ask_cep', firstContactAt, leadCreatedAt };
    return finalPayload(state, {
      customerMessage: `Ótimo. Agora me envie o *CEP de entrega* com 8 números para eu calcular o frete.\n\n_Ex.: 37550360_`,
      sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'coleta_cep'
    });
  }

  if (stage === 'ask_cep') {
    const cep = onlyDigits(msg);
    if (cep.length !== 8) {
      return finalPayload(state, {
        customerMessage: `CEP inválido.\n\nPor favor, envie somente os 8 números do CEP.`,
        sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'validacao_cep'
      });
    }
    const cepData = await consultarCep(cep);
    if (!cepData) {
      return finalPayload(state, {
        customerMessage: `Não consegui validar esse CEP.\n\nPode conferir e enviar novamente?`,
        sendCustomer: true, leadStatus: 'coletando_dados', eventType: 'cep_nao_encontrado'
      });
    }
    const quantity = Number(state.quantity || 0);
    const unitPrice = state.code === 'inox_304' ? CONFIG.price304 : CONFIG.price430;
    const discount = quantity > CONFIG.bonusQtyMin ? Number((quantity * CONFIG.bonusPerPiece).toFixed(2)) : 0;
    const subtotal = Number((quantity * unitPrice).toFixed(2));
    const eligibleFreeShipping = CONFIG.freeShippingStates.includes(cepData.uf) && quantity >= CONFIG.freeShippingQtyAbove;
    const specialCondition = quantity > CONFIG.specialConditionQtyAbove;

    let shipping;
    if (eligibleFreeShipping) {
      shipping = { mode: 'free', label: `Frete grátis para ${cepData.uf} em pedidos acima de 100 unidades.`, price: 0, service: 'Frete grátis', deliveryRange: null };
    } else {
      shipping = await cotarMelhorEnvio(cep, quantity, unitPrice);
    }

    const total = Number((subtotal - discount + (shipping.price || 0)).toFixed(2));
    const deliveryText = shipping.deliveryRange?.min
      ? `Prazo estimado: ${shipping.deliveryRange.min}${shipping.deliveryRange.max && shipping.deliveryRange.max !== shipping.deliveryRange.min ? ` a ${shipping.deliveryRange.max}` : ''} dia(s) úteis`
      : null;
    const shippingText = shipping.mode === 'free'
      ? 'Frete grátis'
      : shipping.mode === 'quoted'
        ? `${shipping.service}: ${formatMoney(shipping.price)}`
        : 'Vamos cotar o melhor envio para sua região';

    const quoteLines = [
      `💼 *Orçamento ${CONFIG.companyName}*`,
      ``,
      `🔩 Produto: ${CONFIG.productName}`,
      `• Material: ${state.label}`,
      `• Espessura do porcelanato: ${state.thicknessLabel}`,
      `• Quantidade: ${quantity} unidade(s)`,
      `• Cada peça acompanha bucha prego`,
      ``,
      `━━━━━━━━━━━━━━`,
      `💰 *Resumo financeiro*`,
      `• Valor unitário: ${formatMoney(unitPrice)}`,
      `• Subtotal: ${formatMoney(subtotal)}`,
      quantity > CONFIG.bonusQtyMin ? `• Bônus por volume: -${formatMoney(discount)}` : null,
      shipping.mode === 'free' ? `• Frete: ${shipping.label}` : null,
      shipping.mode === 'quoted' ? `• Frete (${shipping.service}): ${formatMoney(shipping.price)}` : null,
      shipping.mode === 'manual' ? `• Frete: ${shipping.label}` : null,
      `• Total estimado: *${formatMoney(total)}*`,
      ``,
      `📍 Entrega: ${cepData.localidade}/${cepData.uf}`,
      deliveryText,
      specialCondition ? `⭐ *Condições especiais para pedidos acima de 200 unidades.*` : null,
      `🔗 Comprar agora: ${CONFIG.pagbankUrl}`,
      ``,
      `✅ Orçamento enviado! Nosso consultor entrará em contato em breve pelo WhatsApp para finalizar seu pedido.\n\n_Horário de atendimento: seg–sex, 8h–18h._`
    ].filter(Boolean);

    state = {
      ...state, stage: 'human', mode: 'human', cep,
      city: cepData.localidade, state: cepData.uf,
      bairro: cepData.bairro, street: cepData.logradouro,
      specialCondition, shipping, subtotal, discount, total, unitPrice,
      firstContactAt, leadCreatedAt
    };

    return finalPayload(state, {
      customerMessage: quoteLines.join('\n'),
      sellerMessage: buildSellerLeadMessage({
        ...state, phone: incoming.phone, name: incoming.name,
        inoxLabel: state.label, shippingText, totalText: formatMoney(total),
        stage: 'aguardando_humano'
      }, 'Lead pronto para fechamento'),
      sendCustomer: true, sendSeller: true,
      leadStatus: 'aguardando_humano',
      quote: { inox: state.label, thickness: state.thicknessLabel, quantity, unitPrice, subtotal, discount, shipping, total, city: cepData.localidade, state: cepData.uf, cep, pagbankUrl: CONFIG.pagbankUrl },
      eventType: 'orcamento_enviado'
    });
  }

  return finalPayload({ stage: 'menu', mode: 'bot', firstContactAt, leadCreatedAt }, {
    customerMessage: menuMessage(), sendCustomer: true,
    leadStatus: 'menu', eventType: 'fallback_menu'
  });
}

return await main();

const https = require('https');
const data = $input.first().json;

function sendZapi(phone, message) {
  const instanceId = '3F014370287EB1AB0ED286AA524A00CF';
  const instanceToken = '6FBA0FCAFFDF48D8EB5C5414';
  const clientToken = 'F4ac7d6e0b24c463684ed01e82e71757fS';

  if (!instanceId || !instanceToken || !clientToken) {
    return Promise.resolve({ ok: false, reason: 'Configure ZAPI_INSTANCE_ID, ZAPI_INSTANCE_TOKEN e ZAPI_CLIENT_TOKEN.' });
  }
  if (!phone || !message) {
    return Promise.resolve({ ok: false, reason: 'Telefone ou mensagem ausente.' });
  }

  const body = JSON.stringify({ phone, message });

  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.z-api.io',
      path: `/instances/${instanceId}/token/${instanceToken}/send-text`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Client-Token': clientToken,
        'Content-Length': Buffer.byteLength(body)
      }
    }, (res) => {
      let raw = '';
      res.on('data', chunk => raw += chunk);
      res.on('end', () => {
        let parsed = null;
        try { parsed = raw ? JSON.parse(raw) : null; } catch (e) {}
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, statusCode: res.statusCode, data: parsed, raw });
      });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

const logs = [];

if (data.sendCustomer && data.customerMessage) {
  const r = await sendZapi(data.phone, data.customerMessage);
  logs.push({ target: 'cliente', phone: data.phone, result: r });
}

if (data.sendSeller && data.sellerMessage) {
  const r = await sendZapi('5535999619463', data.sellerMessage);
  logs.push({ target: 'comercial', phone: '5535999619463', result: r });
}

return [{ json: { ...data, deliveryLogs: logs } }];
